        if p == "deathplace":
            return f"died in {clean_obj_val}" if combine_with_prev else f"{subj} died in {clean_obj_val}"
        if p == "deathcause":
            return f"died of {clean_obj_val}" if combine_with_prev else f"{subj} died of {clean_obj_val}"
        if p == "nationality" or p == "stateoforigin":
            return f"is from {clean_obj_val}" if combine_with_prev else f"{subj} is from {clean_obj_val}"
        if p == "almamater":
            return f"studied at {clean_obj_val}" if combine_with_prev else f"{subj} studied at {clean_obj_val}"
