        main_text = ", ".join(main_clauses[:-1]) + ", and " + main_clauses[-1] if len(main_clauses) > 1 else main_clauses[0]
        related_text = ", ".join(related_clauses[:-1]) + ", and " + related_clauses[-1] if len(related_clauses) > 1 else related_clauses[0]
        sentence = main_text + ", " + related_text + "."
